   594→// ValidSnapshotEntries returns all the valid snapshot entries in the wal logs in the given directory.
   595→// Snapshot entries are valid if their index is less than or equal to the most recent committed hardstate.
   596→func ValidSnapshotEntries(lg *zap.Logger, walDir string) ([]walpb.Snapshot, error) {
   597→	var snaps []walpb.Snapshot
   598→	var state raftpb.HardState
   599→	var err error
   600→
   601→	rec := &walpb.Record{}
   602→	names, err := readWALNames(lg, walDir)
   603→	if err != nil {
   604→		return nil, err
   605→	}
   606→
   607→	// open wal files in read mode, so that there is no conflict
   608→	// when the same WAL is opened elsewhere in write mode
   609→	rs, _, closer, err := openWALFiles(lg, walDir, names, 0, false)
   610→	if err != nil {
   611→		return nil, err
   612→	}
   613→	defer func() {
   614→		if closer != nil {
   615→			closer()
   616→		}
   617→	}()
   618→
   619→	// create a new decoder from the readers on the WAL files
   620→	decoder := NewDecoder(rs...)
   621→
   622→	for err = decoder.Decode(rec); err == nil; err = decoder.Decode(rec) {
   623→		switch rec.GetType() {
   624→		case SnapshotType:
   625→			var loadedSnap walpb.Snapshot
   626→			pbutil.MustUnmarshal(&loadedSnap, rec.Data)
   627→			snaps = append(snaps, loadedSnap)
   628→		case StateType:
   629→			state = MustUnmarshalState(rec.Data)
   630→		case CrcType:
   631→			crc := decoder.LastCRC()
   632→			// current crc of decoder must match the crc of the record.
   633→			// do no need to match 0 crc, since the decoder is a new one at this case.
   634→			if crc != 0 && rec.Validate(crc) != nil {
   635→				return nil, ErrCRCMismatch
   636→			}
   637→			decoder.UpdateCRC(rec.GetCrc())
   638→		}
   639→	}
   640→	// We do not have to read out all the WAL entries
   641→	// as the decoder is opened in read mode.
   642→	if !errors.Is(err, io.EOF) && !errors.Is(err, io.ErrUnexpectedEOF) {
   643→		return nil, err
   644→	}
