   264→			zap.Int64("backend-size-in-use-bytes", s2),
   265→			zap.String("backend-size-in-use", humanize.Bytes(uint64(s2))),
   266→		)
   267→		if err = schema.Validate(cfg.Logger, be.ReadTx()); err != nil {
   268→			cfg.Logger.Error("Failed to validate schema", zap.Error(err))
   269→			return nil, err
   270→		}
   271→	}
   272→
   273→	return &bootstrappedBackend{
   274→		beHooks:  beHooks,
   275→		be:       be,
   276→		ci:       ci,
   277→		beExist:  beExist,
   278→		snapshot: snapshot,
   279→	}, nil
   280→}
